   130			return nil, nil, fmt.Errorf("exec definition %q has invalid executor kind %q", def.ID, def.Executor.Kind)
   131		}
   132		if def.Executor.Kind == ExecutorKindCommand && len(def.Executor.Command) == 0 {
   133			return nil, nil, fmt.Errorf("exec definition %q has no command", def.ID)
   134		}
   135		if graph == nil {
   136			graph, err = s.buildGraph()
   137			if err != nil {
   138				return nil, nil, err
   139			}
   140		}
   141		var primary *docgraph.Document
   142		for _, artifactID := range def.ArtifactIDs {
