   378	func (s *Store) saveDefinitionBead(def Definition) error {
   379		if s.DefinitionCollection == nil {
   380			return fmt.Errorf("exec definition collection not initialized")
   381		}
   382		return s.DefinitionCollection.WithLock(func() error {
   383			beads, err := s.DefinitionCollection.ReadAll()
   384			if err != nil {
   385				return err
   386			}
   387			current := definitionBead(def)
   388			replaced := false
   389			for i := range beads {
   390				if beads[i].ID == current.ID {
   391					beads[i] = current
   392					replaced = true
   393					break
   394				}
   395			}
   396			if !replaced {
   397				beads = append(beads, current)
   398			}
   399			return s.DefinitionCollection.WriteAll(beads)
   400		})
   401	}
