   404		if s.RunCollection == nil {
   405			return fmt.Errorf("exec run collection not initialized")
   406		}
   407		if rec.RunID == "" {
   408			return fmt.Errorf("run_id is required")
   409		}
   410		if rec.DefinitionID == "" {
   411			return fmt.Errorf("definition_id is required")
   412		}
   413		if rec.Attachments == nil {
   414			rec.Attachments = make(map[string]string)
   415		}
   416		rec.Attachments["stdout"] = runAttachmentRef(s.WorkingDir, rec.RunID, "stdout.log")
   417		rec.Attachments["stderr"] = runAttachmentRef(s.WorkingDir, rec.RunID, "stderr.log")
   418		rec.Attachments["result"] = runAttachmentRef(s.WorkingDir, rec.RunID, "result.json")
   419	
   420		attachmentRoot := filepath.Join(s.WorkingDir, ".ddx", execRunAttachmentDir)
   421		if err := os.MkdirAll(attachmentRoot, 0o755); err != nil {
   422			return err
   423		}
   424		tempDir, err := os.MkdirTemp(attachmentRoot, ".tmp-")
   425		if err != nil {
   426			return err
   427		}
   428		defer os.RemoveAll(tempDir)
   429	
   430		manifestRaw, err := json.MarshalIndent(rec.RunManifest, "", "  ")
   431		if err != nil {
   432			return err
   433		}
   434		resultRaw, err := json.MarshalIndent(rec.Result, "", "  ")
   435		if err != nil {
   436			return err
   437		}
   438		if err := os.WriteFile(filepath.Join(tempDir, "manifest.json"), manifestRaw, 0o644); err != nil {
   439			return err
   440		}
   441		if err := os.WriteFile(filepath.Join(tempDir, "result.json"), resultRaw, 0o644); err != nil {
   442			return err
   443		}
   444		if err := os.WriteFile(filepath.Join(tempDir, "stdout.log"), []byte(rec.Result.Stdout), 0o644); err != nil {
   445			return err
   446		}
   447		if err := os.WriteFile(filepath.Join(tempDir, "stderr.log"), []byte(rec.Result.Stderr), 0o644); err != nil {
   448			return err
   449		}
   450		if err := syncPath(tempDir); err != nil {
   451			return err
   452		}
   453	
   454		return s.RunCollection.WithLock(func() error {
   455			finalDir := filepath.Join(attachmentRoot, rec.RunID)
   456			if err := os.Rename(tempDir, finalDir); err != nil {
   457				return err
   458			}
   459			if err := syncPath(attachmentRoot); err != nil {
   460				return err
   461			}
   462			beads, err := s.RunCollection.ReadAll()
   463			if err != nil {
   464				return err
   465			}
   466			current := runBead(rec)
   467			replaced := false
   468			for i := range beads {
   469				if beads[i].ID == current.ID {
   470					beads[i] = current
   471					replaced = true
   472					break
   473				}
   474			}
   475			if !replaced {
   476				beads = append(beads, current)
   477			}
   478			return s.RunCollection.WriteAll(beads)
   479		})
   480	}
